import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

export default function VideoPlayer() {
    const { id } = useParams();
    const [video, setVideo] = useState(null);

    useEffect(() => {
        fetchVideo();
    }, [id]);

    const fetchVideo = async () => {
        try {
            const response = await axios.get(`/videos/${id}/`);
            setVideo(response.data);
        } catch (error) {
            console.error('Error fetching video:', error);
        }
    };

    if (!video) return <div className="text-white text-center">Загрузка...</div>;

    return (
        <div className="container mx-auto px-4 py-8">
            <div className="bg-black rounded-lg overflow-hidden">
                <video controls className="w-full" style={{ maxHeight: '500px' }}>
                    <source src={video.video_file} />
                </video>
            </div>
            <div className="mt-4">
                <h1 className="text-2xl font-bold text-white">{video.title}</h1>
                <p className="text-gray-400 mt-2">{video.description}</p>
                <p className="text-gray-500 mt-2">👁️ {video.views} просмотров</p>
            </div>
        </div>
    );
}
